const Q_CHEMISTRY_1995=[{"id": "objective>Chemistry>1995>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Chromatography is used to separate components of mixtures which differ in their rates of?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">diffusion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">migration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sedimentation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chromatography is a separation technique that is based on the differential migration of the components of a mixture. The components that are more strongly attracted to the stationary phase will move more slowly, while those that are more attracted to the mobile phase will move more quickly.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>1995>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a example of a chemical change?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Dissolution of salt in water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rusting of iron</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Melting of ice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Separating a mixture by distillation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rusting of iron is a chemical change because it results in the formation of a new substance, iron(III) oxide (Fe<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>). Chemical changes involve a process where substance transforms into a new substance with different chemical identity.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : CHEMICAL AND PHYSICAL CHANGES"}, {"id": "objective>Chemistry>1995>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The number of hydrogen ions in 4.9 g of tetraoxosulphate (IV) acid is? <br/> (S = 32, O =16, H = 1, Na = 6.02 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">23</span></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.01 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">22</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.02 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">22</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.01 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">23</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.01 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">23</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Molarmass of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> = 2 × 1) + (1 × 32) + (4 × 16)  <br/> = 2 + 32 + 64 <br/> Molarmass = 98 <br/> no of moles of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> = mole/molarmass <br/> = 4.8/98 <br/> =0.05moles <br/>  <br/> H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> →SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> <br/> From the equation above; <br/> 1mole of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> produced 2moles of H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> <br/>  <br/> This implies that 0.05 mole of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> will produce (2 × 0.05) mole of H+ <br/>  <br/> Therefore  <br/> 1 mole of H+ will produce 6.02×10²³ ions <br/> 0.1 mole of H+ will produce = 6.02×10²³ × 0.1 <br/> = 6.02×10²² ions</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>1995>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What volume of oxygen will remain after reacting 8cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of hydrogen with 20cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of oxygen?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">12 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">14 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">16 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This is the equation of the reaction  <br/> 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O <br/>  <br/> From the equation above; <br/>  <br/> 2cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> requires 1cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>. <br/>  <br/> From the question, 8cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of Hydrogen reacted with 20cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>. <br/>  <br/> We have to find the actual amount of O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> that will react 8cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>. <br/>  <br/> If 2cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> requires 1 cm of O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>. <br/> 8cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of H2 will require xcm of O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>. <br/>  <br/> 2.......1 <br/> 8.......x <br/> cross multiplying, <br/> 2 × x = 1 × 8 <br/> x = 8/2 =4cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>. <br/>  <br/>  <br/> Therefore the volume of oxygen remaining = 20cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> - 4cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/>                   = 16cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "CHEMICAL COMBINATION : GAY LUSSAC'S LAW OF COMBINING VOLUMES"}, {"id": "objective>Chemistry>1995>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A gas sample with an initial volume of 3.25 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> is heated and allowed to expand to 9.75 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> at constant pressure. What is the ratio of the final absolute temperature to the initial absolute temperature?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5:2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5:4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8:3</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">V1= 3.25 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>, V2= 9.75 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>, T1= ?, T2=? <br/> V1/T1=V2/T2 is equal V1/V2=T1/T2 <br/> 3.25/9.75=T1/T2 <br/> 1/3=T1/T2 <br/> T2:T1=3:1</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : COMBINED GAS LAW,MOLAR VOLUME AND ATOMICITY OF GASES"}, {"id": "objective>Chemistry>1995>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two cylinders A and B each contains 30 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of oxygen and nitrogen respectively at the same temperature and pressure. If there are 5.0 moles of nitrogen, then the mass of oxygen is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.2 g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.4 g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">80.0 g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">160.0 g</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">since they both have the same volume,temperature, and pressure it means avogadro's law is being obeyed which means they will have the same number of moles <br/>  <br/> Since 1mole of oxygen gas is 32g <br/> 5*32=160g</div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>1995>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A liquid begins to boil when?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">its vapour pressure is equal to the vapour pressure of its solid at the given temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">molecules start escaping from its surface</div>", "<div style=\"font-family:Cambria;font-size:17px;\">its vapour pressure equals the atmosphere pressure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">its volume is sightly increased</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A liquid begins to boil when its vapour pressure equals the atmospheric pressure. At this point, the liquid is converting to gas at a rate that creates a vapor pressure that is in equilibrium with the pressure of the surrounding atmosphere.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>1995>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A particle that contains 8 protons, 9 neutrons and 7 electrons could be written as?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">16</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">17</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>O<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">17</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">9</span>O<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">17</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>O<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Since there are are 8 protons, there should be 8 electrons. No of neutrons =9. Total mass number=17. Since the electron is 7. Therefore the particle has excess proton of 1(+)</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>1995>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the section of the periodic table below to answer the question <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">2L</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">3G</td><td style=\"border:1px solid black;text-align:center;\">x</td><td style=\"border:1px solid black;text-align:center;\">5</td><td style=\"border:1px solid black;text-align:center;\">6</td><td style=\"border:1px solid black;text-align:center;\">7</td><td style=\"border:1px solid black;text-align:center;\">8J</td><td style=\"border:1px solid black;text-align:center;\">9E</td><td style=\"border:1px solid black;text-align:center;\">10</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">11</td><td style=\"border:1px solid black;text-align:center;\">12M</td><td style=\"border:1px solid black;text-align:center;\">13R</td><td style=\"border:1px solid black;text-align:center;\">14</td><td style=\"border:1px solid black;text-align:center;\">15</td><td style=\"border:1px solid black;text-align:center;\">16T</td><td style=\"border:1px solid black;text-align:center;\">17</td><td style=\"border:1px solid black;text-align:center;\">18</td></tr></table></div> <br/>  <br/> Which of the letters indicate an alkali metal and a noble gas respectively?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">M and E</div>", "<div style=\"font-family:Cambria;font-size:17px;\">G and E</div>", "<div style=\"font-family:Cambria;font-size:17px;\">R and L</div>", "<div style=\"font-family:Cambria;font-size:17px;\">G and L</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The alkali metals consist of the chemical elements lithium (Li), sodium (Na), potassium (K), rubidium (Rb), caesium (Cs), and francium (Fr).They occupy the first column of the periodic table. <br/>  <br/> Noble gases are also called rare gases or inert gases.There are seven noble gas elements: helium, neon, argon, krypton, xenon, radon, and oganesson.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>1995>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the section of the periodic table below to answer the question <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">2L</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">3G</td><td style=\"border:1px solid black;text-align:center;\">x</td><td style=\"border:1px solid black;text-align:center;\">5</td><td style=\"border:1px solid black;text-align:center;\">6</td><td style=\"border:1px solid black;text-align:center;\">7</td><td style=\"border:1px solid black;text-align:center;\">8J</td><td style=\"border:1px solid black;text-align:center;\">9E</td><td style=\"border:1px solid black;text-align:center;\">10</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">11</td><td style=\"border:1px solid black;text-align:center;\">12M</td><td style=\"border:1px solid black;text-align:center;\">13R</td><td style=\"border:1px solid black;text-align:center;\">14</td><td style=\"border:1px solid black;text-align:center;\">15</td><td style=\"border:1px solid black;text-align:center;\">16T</td><td style=\"border:1px solid black;text-align:center;\">17</td><td style=\"border:1px solid black;text-align:center;\">18</td></tr></table></div> <br/> Which letter represents a non-metal that is a solid at room temperature?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">T</div>", "<div style=\"font-family:Cambria;font-size:17px;\">R</div>", "<div style=\"font-family:Cambria;font-size:17px;\">J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">X</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">T  represents a non-metal that is a solid at room temperature. Sulphur</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>1995>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the oil drop experiment, Millikan determined the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">charge to mass ratio of the electron</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> mass of the electron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">charge of the electron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mass of the proton</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The oil drop experiment allowed Millikan to determine the charge on the electron. He later used this data to determine the mass of the electron.Hence, Millikan's oil drop experiment establishes that the electric charge is quantized.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>1995>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The stability of ionic solids is generally due to the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">negative electron affinity of most atoms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">crystal lattice forces</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> electron pair sharing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">positive ionization potentials</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The stability of ionic solids is generally due to the crystal lattice forces. These forces are the attractive forces between the positive and negative ions in the ionic solid. They hold the ions in a fixed pattern in the crystal lattice, giving the solid its stability.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>1995>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements is FALSE about isotopes of the same element?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> They have the same number of electrons in their outermost shells</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They have different atomic masses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They have the same atomic number and the number of electrons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They have the same atomic number but different number of electrons</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Isotopes of the same element have the same atomic number and hence the same number of electrons. Therefore, the statement 'They have the same atomic number but different number of electrons' is false.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>1995>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Helium is often used in observation balloons because it is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">light and combustible</div>", "<div style=\"font-family:Cambria;font-size:17px;\">light and non-combustible</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> heavy and combustible</div>", "<div style=\"font-family:Cambria;font-size:17px;\">heavy and non-combustible</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Helium is often used in observation balloons because it is light and non-combustible. Being lighter than air, it provides the lift needed for the balloon. Being non-combustible, it does not pose a fire risk.</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>1995>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When plastics and packaging materials made from chloroethene are burnt in the open, the mixture of gases released into the atmosphere is most likely to contain?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ethane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chlorine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen chloride</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethene</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When plastics and packaging materials made from chloroethene are burnt in the open, the mixture of gases released into the atmosphere is most likely to contain hydrogen chloride. This is because chloroethene (also known as vinyl chloride) is a compound of hydrogen, carbon, and chlorine, and when it is burnt, it breaks down to form hydrogen chloride among other products.</div>", "topic": "ENVIRONMENTAL POLLUTION : AIR POLLUTION"}, {"id": "objective>Chemistry>1995>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Deliquescent substances are also?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">efflorescent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">anhydrous</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hygroscopic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">insoluble</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Deliquescent substances are also hygroscopic. Both deliquescent and hygroscopic substances absorb moisture from the air, but deliquescent substances do so to a much greater extent, often becoming liquid.</div>", "topic": "WATER : WATER OF CRYSTALLIZATION EFFLORESENCE DELIQUESCENCE AND HYGROSCOPY"}, {"id": "objective>Chemistry>1995>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The difference between colloids and and suspensions is brought out clearly by the fact that while colloids?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">do not scatter light, suspensions do</div>", "<div style=\"font-family:Cambria;font-size:17px;\">can be separated by filtration, suspension cannot be so separated</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> can be separated by a membrane, suspensions cannot</div>", "<div style=\"font-family:Cambria;font-size:17px;\">do not settle out on standing, suspensions do</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The difference between colloids and suspensions is brought out clearly by the fact that while colloids do not settle out on standing, suspensions do. Suspensions are heterogeneous mixtures with large, often visible solutes that tend to settle out. Colloids, on the other hand, are mixtures where the solute particles are smaller and do not settle out.</div>", "topic": "SOLUBILITY : SUSPENSIONS AND COLLOIDS"}, {"id": "objective>Chemistry>1995>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In general, an increase in temperature increases the solubility of a solute in water because?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">more solute molecules collide with each other</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> most solutes dissolve with the evolution of heat</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> more solute molecules dissociate at higher temperatures</div>", "<div style=\"font-family:Cambria;font-size:17px;\">most solutes dissolve with absorption of heat</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In general, an increase in temperature increases the solubility of a solute in water because most solutes dissolve with absorption of heat. This is an endothermic process, and increasing the temperature provides more heat for the process, thus increasing the solubility.</div>", "topic": "SOLUBILITY : UNSATURATED SATURATED AND SUPERSATURATED SOLUTIONS"}, {"id": "objective>Chemistry>1995>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Neutralization involves a reaction between H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>O<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> and?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cl<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Neutralization involves a reaction between H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>O<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> (hydronium ion) and OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> (hydroxide ion). The reaction produces water and is the basis for the concept of acid-base neutralization.</div>", "topic": "ACID BASE AND SALTS : ACID AND BASE TITRATIONS"}, {"id": "objective>Chemistry>1995>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following solution will have a pH< 7?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NaCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A solution with a pH less than 7 is acidic. NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>Cl is an ammonium salt, which when dissolved in water, forms a weak acid (ammonium ion) and a strong base (chloride ion). The weak acid does not ionize completely, resulting in a solution with a pH less than 7.</div>", "topic": "ACID BASE AND SALTS : PH AND POH SCALE"}, {"id": "objective>Chemistry>1995>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the pH of a 2.50 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>M solution of sodium hydroxide?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.6</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12.0</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Kw = [H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>][OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>]=10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-14</span>=[H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>][2.50 * [10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>] <br/> [H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>] = 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-14</span>/2.50 * 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span> <br/> [H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>]= 4 * 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-10</span> <br/> pH = -log [ 4 * 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-10</span>]=9.4 <br/> or <br/> pOH=-log(2.50 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span> <br/> pOH=4.6 <br/> pOH + pH=14 <br/> pH=14-4.6 <br/> pH=9.4</div>", "topic": "ACID BASE AND SALTS : PH AND POH SCALE"}, {"id": "objective>Chemistry>1995>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The graph above shows the pH changes for the titration of a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">strong acid versus strong base</div>", "<div style=\"font-family:Cambria;font-size:17px;\">weak acid versus strong base</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> strong acid versus weak base</div>", "<div style=\"font-family:Cambria;font-size:17px;\">weak acid versus weak base</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The graph above shows the pH changes for the titration of a weak acid versus strong base</div>", "topic": "ACID BASE AND SALTS : ACID AND BASE TITRATIONS"}, {"id": "objective>Chemistry>1995>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the process of silver-plating a metal M, the metal M is the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">anode and a direct current is used</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cathode and an alternating current is used</div>", "<div style=\"font-family:Cambria;font-size:17px;\">anode and an alternating current is used</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cathode and a direct current is used</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A direct current is passed into the set up of electroplating of metal M by placing it in cathode. During electrolysis, it is a direct current that is passed through the electrolytes</div>", "topic": "ELECTROLYSIS : ELECTROCHEMICAL CELLS"}, {"id": "objective>Chemistry>1995>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many moles of copper would be deposited by passing 3F of electricity through a solution of copper (II) tetraoxosulpohate (IV)? <br/>  <br/> (F = 96 500 <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.0</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> → Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> + SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> <br/> Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>→  Cu at the cathode <br/> 2F will deposit 1 mole of Cu <br/> ∴  3F will deposit (1 * 3F)/2F mole of Cu =1.5 moles of Cu</div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>1995>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">2Cl<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → CI<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + 2e<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span>. The above half-cell reaction occuring at the anode during the electrolysis of dilute ZnCI2 solution is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ionization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxidation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">recombination</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The given half-cell reaction is an oxidation process. Oxidation is the loss of electrons, and in the given reaction, chloride ions (Cl<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>) are losing electrons to form chlorine gas (Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>).</div>", "topic": "ELECTROLYSIS : FACTORS AFFECTING DISCHARGE OF IONS AT THE ELECTRODES"}, {"id": "objective>Chemistry>1995>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a redox reaction?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> KCI<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → KHSO4<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + HCI<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2FeBr2<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + Br<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → 2FeBr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">3AgNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + FeCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → 3AgCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + Fe(NO3)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(I)</span> + CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A redox reaction is a type of chemical reaction that involves a transfer of electrons between two species. In the given options, the reaction 2FeBr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(aq)</span> + Br2(aq) → 2FeBr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(aq)</span> is a redox reaction. In this reaction, iron (Fe) is oxidized from +2 to +3 oxidation state and bromine (Br) is reduced from 0 to -1 oxidation state.</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>1995>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Cr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + 14H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + 6l<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → 2Cr<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + 3l<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + 7H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(I)</span>. <br/> The change in the oxidation number of oxygen in the equation above is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The oxidation number of oxygen in most compounds is -2. In the given reaction, the oxidation number of oxygen in Cr2O7<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> is -2 and in H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O is also -2. Therefore, there is no change in the oxidation number of oxygen, so the answer is 0.</div>", "topic": "OXIDATION AND REDUCTION : REDUCTION"}, {"id": "objective>Chemistry>1995>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If an equilibrium reaction has ∆H < O, the reaction will proceed favorably in the forward reaction at?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">low temperatures</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high temperatures</div>", "<div style=\"font-family:Cambria;font-size:17px;\">all temperatures</div>", "<div style=\"font-family:Cambria;font-size:17px;\">all pressures</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If an equilibrium reaction has ∆H < 0, it means the reaction is exothermic, i.e., it releases heat. According to Le Chatelier's principle, an exothermic reaction is shifted to the right (products side) by a decrease in temperature. Therefore, the reaction will proceed favorably in the forward direction at low temperatures.</div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>1995>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following processes leads to increase in entropy?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mixing a sample of NaCl and sand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Condensation of water vapour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Boiling a sample of water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cooling a saturated solution</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Entropy is a measure of the disorder or randomness of a system. The process that leads to an increase in entropy is the one that increases the disorder of the system. Boiling a sample of water increases the disorder as the water molecules move from a relatively ordered liquid state to a more disordered gaseous state.</div>", "topic": "ENERGY CHANGES : ENTROPY"}, {"id": "objective>Chemistry>1995>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following equilibria is shifted to the right as a result of an increase in pressure?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + I<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> ⇌ 2HI<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"> 2NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> ⇌  N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">PCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> ⇌  PCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"> 2O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> ⇌  3O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Le Chatelier's principle, an increase in pressure shifts the equilibrium towards the side with fewer moles of gas. In the given options, the reaction 2NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(g)</span> has fewer moles of gas on the right side (product side), so an increase in pressure will shift the equilibrium to the right.</div>", "topic": "CHEMICAL EQUILIBRA : LE CHATELIER'S PRINCIPLE AND EQUILIBRIUM CONSTANT"}, {"id": "objective>Chemistry>1995>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The arrangement above can be used for the collection of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sulphur (IV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> ammonia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen chloride</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrogen</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This is the setup for the laboratory preparation of Nitrogen gas.Nitrogen is not very soluble in H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O and it can be collected through \"DOWNWARD DISPLACEMENT AND UPWARD \"(As shown in the diagram) ; <br/> SO2 can only be through \"DOWNWARD DELIVERY\" but not through \"DOWNWARD DISPLACEMENT AND UPWARD DELIVERY\" (as represented in the diagram) ; <br/> HCL AND NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> are very soluble in H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O and cannot be collected through it because they will dissolve in H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>1995>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The activation energy of the uncatalysed reaction is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">X</div>", "<div style=\"font-family:Cambria;font-size:17px;\">X + Y</div>", "<div style=\"font-family:Cambria;font-size:17px;\">X - Y</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Y</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The activation energy of the uncatalysed reaction is X</div>", "topic": "RATE OF CHEMICAL REACTION : ACTIVATION ENERGY"}, {"id": "objective>Chemistry>1995>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> It can be deduced that the rate of the reaction?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">for path l is higher than path ll</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> for path ll is higher than path l</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is the same for both paths at all temperatures</div>", "<div style=\"font-family:Cambria;font-size:17px;\">depends on the values of both x and y at all pressures</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The higher the activation energy, the slower the chemical reaction will be. <br/> The activation energy for path I is greater than the activation energy for path II. This means that the rate of reaction for path II is greater than path I. <br/> i. The thick line represents UNCATALYSED part <br/> ii. The dotted line represents CATALYSED part</div>", "topic": "RATE OF CHEMICAL REACTION : FACTORS"}, {"id": "objective>Chemistry>1995>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the industrial production of hydrogen from natural gas, carbon (IV) oxide produced along with the hydrogen is removed by?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">washing with water under pressure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">passing the mixture into lime water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">using ammoniacal copper (l) chloride</div>", "<div style=\"font-family:Cambria;font-size:17px;\">drying over phosphorus (V) oxide</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the industrial production of hydrogen from natural gas, the carbon (IV) oxide produced along with the hydrogen is removed by washing with water under pressure. This process is known as water-gas shift reaction, where carbon monoxide reacts with water to form carbon dioxide and hydrogen.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : CARBON"}, {"id": "objective>Chemistry>1995>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Sulphur exists in six forms in the solid state. This property is known as?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">isomerism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">allotropy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">isotopy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">isomorphism</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Allotropy is the property of some chemical elements to exist in two or more different forms, in the same physical state, known as allotropes of these elements. Sulphur exists in six forms in the solid state, which is an example of allotropy.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE CONCEPT OF ATOMS, MOLECULES AND IONS"}, {"id": "objective>Chemistry>1995>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A gas that will turn orange potassium heptaoxodichromate (VI) solution to clear green is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sulphur (VI) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen sulphide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sulphur (lV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen chloride</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sulphur (lV) oxide is the gas. This is because SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is a reducing agent.</div>", "topic": "OXIDATION AND REDUCTION : TEST FOR OXIDIZING AND REDUCING AGENTS"}, {"id": "objective>Chemistry>1995>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following ions will give a white precipitate with aqueous NaOH and soluble in excess of the base?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> Ca<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zn<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Zinc ions (Zn<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span>) will give a white precipitate with aqueous NaOH and soluble in excess of the base. This is because zinc hydroxide, which is formed initially, is amphoteric in nature and dissolves in excess sodium hydroxide to form a complex ion.</div>", "topic": "ACID BASE AND SALTS : QUALITATIVE COMPARISON"}, {"id": "objective>Chemistry>1995>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the extraction of iron in the blast furnace, limestone is used to?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">release CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> for the reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce the iron ore</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase the strength of the iron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remove impurities</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the extraction of iron in the blast furnace, limestone is used to remove impurities. The limestone decomposes to form calcium oxide, which reacts with the impurities to form slag, which is then removed.</div>", "topic": "METALS AND THEIR COMPOUNDS : IRON"}, {"id": "objective>Chemistry>1995>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following compounds will impart a brick-red colour to a non-luminous bunsen flame?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NaCl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">LiCl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CaCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">MgCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Calcium chloride (CaCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>) will impart a brick-red colour to a non-luminous bunsen flame. This is due to the characteristic flame colour of calcium ions when they are heated.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>1995>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Group 1 A metals are not found free in nature because they?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">are of low melting and boiling points</div>", "<div style=\"font-family:Cambria;font-size:17px;\">have weak metallic bonding</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conduct electricity and heat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are very reactive</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Group 1 A metals are not found free in nature because they are very reactive. They readily react with oxygen and moisture present in the air, hence they are usually found in combined state in nature.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALKALI METALS"}, {"id": "objective>Chemistry>1995>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH + CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>OH → X + Y. X and Y in the reaction are respectively</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COCH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> and H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>COCH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> and H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOCH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> and H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CHO and CH</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOCH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> and H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O. The reaction is an esterification reaction. Esterification reaction is a reaction between an alkanol and an alkanoic acid forming an alkanoate(ester) and water.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOATES"}, {"id": "objective>Chemistry>1995>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">CHCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> + Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → HCl + CCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>. The reaction is an example of?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an addition reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a substitution reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> a chlorination reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a condensation reaction</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction is an example of a substitution reaction, where one or more atoms or groups in a molecule are replaced by other atoms or groups. In this case, a hydrogen atom in chloroform is replaced by a chlorine atom to form carbon tetrachloride.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>1995>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">CH-CH-CH=CH-CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> <br/> &nbsp &nbsp &nbsp &nbsp&nbsp | <br/> &nbsp &nbsp &nbsp &nbsp CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> <br/>  <br/> The IUPAC  nomenclature for the compound above is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1,1-dimethylbut-ene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2-methylpent-3-ene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4,4-dimethylbut-ene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4-methylpent-2-ene</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The IUPAC nomenclature for the compound is 4-methylpent-2-ene. According to IUPAC rules, the longest carbon chain containing the double bond is selected as the parent chain. The numbering is done in such a way that the double bond gets the lowest possible number. The methyl group is at the 4th position of the parent chain, hence the name 4-methylpent-2-ene.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>1995>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following pairs has compounds that are isomers?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Propanal and propanone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ethanoic acid and ethylmethanoate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ethanoic acid and ethane-1, 2-diol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2-methylbutane and 2, 2-dimethylbutane</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">propanal and propanone;both have the formula C3H6O. They are functional isomers of each other with the functional group C=O</div>", "topic": "ORGANIC COMPOUNDS : ALKANOIC ACIDS"}, {"id": "objective>Chemistry>1995>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Aromatic and aliphatic hydrocarbons can be distinguished from each other by the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">action of bromine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">use of polymerization reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> action of heat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">use of oxidation reaction</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Aromatic hydrocarbon produces smoky flame while aliphatic do not. And this is observed by applying heat.</div>", "topic": "ORGANIC COMPOUNDS : AROMATIC HYDROCARBONS"}, {"id": "objective>Chemistry>1995>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The role of sodium chloride in the preparation of soap is to?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> purify the soap</div>", "<div style=\"font-family:Cambria;font-size:17px;\">separate the soap from glycerol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">accelerate the decomposition of the fat or oil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">react with glycerol</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the preparation of soap, sodium chloride is used to separate the soap from glycerol. This is done by 'salting out' the soap, a process where sodium chloride is added to the soap mixture, causing the soap to precipitate out of the solution.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOATES"}, {"id": "objective>Chemistry>1995>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The functional group represented in the compound above is? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">alkanol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanoate</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The name of the compound is butenal ( a carbonyl-containing compound of aldehyde not ketone) because the functional group (CHO) is at the end of the carbon chain not inbetween, therefore it is an Alkanal </div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>1995>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">Y</span> + 4O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → 3CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O. The hydrocarbon, C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">Y</span>, in the reaction above is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">propane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">propene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">propyne</div>", "<div style=\"font-family:Cambria;font-size:17px;\">propanone</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span>+(x+y/4)O2 --------- xCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>+y/2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O <br/> from the equation x=3 <br/> 3+y/4=4 <br/> multiply both sides by 4 <br/> 3×4+y×4/4=4×4 <br/> 12+y=16 <br/> y=16-12=4 <br/> y=4 <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>+(3+4/4)O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> ---------- 3CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>+4/2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>+4O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> --------- 3CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>+2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> is propyne</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>1995>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of a secondary amine is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">propylene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">di-butylamine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">methylamine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trimethylamine</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Secondary amines have the nitrogen atom bonded to two alkyl groups and one hydrogen atom. Di-butylamine is a secondary amine because it has the nitrogen atom bonded to two butyl groups and one hydrogen atom.</div>", "topic": "ORGANIC COMPOUNDS : AMINES"}, {"id": "objective>Chemistry>1995>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The relatively high boiling points of alkanols are due to?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> ionic bonding</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aromatic character</div>", "<div style=\"font-family:Cambria;font-size:17px;\">covalent bonding</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen bonding</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The relatively high boiling points of alkanols (alcohols) are due to hydrogen bonding. Hydrogen bonding is a strong type of dipole-dipole interaction that occurs when a hydrogen atom bonded to a highly electronegative atom (like oxygen in alcohols) is attracted to another electronegative atom.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}];
